css:
.acl-form { font-family: Arial, Helvetica, sans-serif; font-size: 8pt; color: #000; }
.acl-header { text-align: center; margin-bottom: 8px; }
.acl-title { font-size: 11pt; font-weight: 700; }
.acl-meta span { margin: 0 8px; }
.acl-variants, .acl-ebs { margin-top: 4px; font-size: 9pt; }
.acl-grid, .acl-assessors, .acl-modules { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
.acl-grid th, .acl-grid td, .acl-assessors th, .acl-assessors td, .acl-modules th { border: 1px solid #000; padding: 2px 3px; vertical-align: top; }
.acl-grid-head th { background: #e6e6e6; font-weight: 700; text-align: center; font-size: 7pt; }
.col-no { width: 4%; text-align: center; }
.col-name { width: 14%; }
.col-outcome { min-width: 28px; text-align: center; font-size: 7pt; }
.col-result { text-align: center; font-size: 7pt; }
.acl-footer-notes, .acl-unit-desc { font-size: 7pt; margin: 6px 0; white-space: pre-wrap; }
.acl-form-footer { margin-top: 12px; font-size: 7pt; }
.sig-img { max-height: 24px; max-width: 80px; }
